// RUN: objc3c --verify-interface M19C006B.opt.objcmod M19C006B.opt.obji %s
typedef enum M19C006CompletionStatus {
    M19C006_STATUS_SUCCESS = 0,
    M19C006_STATUS_ERROR = 1,
    M19C006_STATUS_CANCELLED = 2
} M19C006CompletionStatus;

typedef void (*M19C006Completion)(
    void * _Nullable context,
    M19C006CompletionStatus status,
    id _Nullable result,
    id<Error> _Nullable error);

void M19c006_export_async_module_a(int token,
                                   void * _Nullable context,
                                   M19C006Completion _Nonnull completion);
void M19c006_export_async_module_b(int token,
                                   void * _Nullable context,
                                   M19C006Completion _Nonnull completion);
